Multi-step workflows like checkout are prime targets for bypass attacks. Attackers can skip directly to final steps, bypassing payment or validation. Here's a common vulnerable pattern and its secure alternative.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

app.use(express.json());

// Vulnerable: No workflow state validation
let orders = {};
let carts = {};

// Step 1: Review cart
app.post('/api/checkout/review', (req, res) => {
  const { userId, items } = req.body;
  carts[userId] = { items, total: calculateTotal(items) };
  res.json({ success: true, cartId: userId, total: carts[userId].total });
});

// Step 2: Process payment
app.post('/api/checkout/payment', (req, res) => {
  const { userId, paymentMethod } = req.body;
  // Simulated payment processing
  const paymentResult = processPayment(paymentMethod, carts[userId]?.total);
  res.json({ success: paymentResult, transactionId: generateTxId() });
});

// Step 3: Confirm order - VULNERABLE: No verification of previous steps!
app.post('/api/checkout/confirm', (req, res) => {
  const { userId, transactionId } = req.body;

  // Attacker can call this directly without completing payment!
  orders[userId] = {
    items: carts[userId]?.items || [],
    status: 'confirmed',
    transactionId: transactionId
  };

  res.json({ 
    success: true, 
    orderId: generateOrderId(),
    message: 'Order confirmed!' 
  });
});

function calculateTotal(items) {
  return items.reduce((sum, item) => sum + item.price * item.qty, 0);
}

function processPayment(method, amount) { return true; }
function generateTxId() { return 'TX' + Date.now(); }
function generateOrderId() { return 'ORD' + Date.now(); }

app.listen(3000);
```

**Attack Payload**:
```bash
# Skip directly to order confirmation without payment
curl -X POST http://localhost:3000/api/checkout/confirm \
  -H "Content-Type: application/json" \
  -d '{"userId": "attacker123", "transactionId": "FAKE-TX-001"}'

# Response: {"success":true,"orderId":"ORD1704912345678","message":"Order confirmed!"}
```

**Why This Is Dangerous**:
- No verification that cart review step was completed
- No validation that payment was actually processed
- Fake transaction IDs are accepted without verification
- Attackers get free products/services by skipping payment
- Business suffers direct financial losses

**SECURE VERSION**:

```javascript
const express = require('express');
const crypto = require('crypto');
const app = express();

app.use(express.json());

// Secure: Workflow state machine with cryptographic tokens
const workflowStates = {};
const completedPayments = new Map();
const SECRET_KEY = process.env.WORKFLOW_SECRET || crypto.randomBytes(32);

// Generate signed workflow token
function generateWorkflowToken(userId, step, data) {
  const payload = JSON.stringify({ userId, step, data, timestamp: Date.now() });
  const signature = crypto.createHmac('sha256', SECRET_KEY)
    .update(payload)
    .digest('hex');
  return Buffer.from(payload).toString('base64') + '.' + signature;
}

// Verify workflow token
function verifyWorkflowToken(token, expectedStep, userId) {
  try {
    const [payloadB64, signature] = token.split('.');
    const payload = Buffer.from(payloadB64, 'base64').toString();
    const expectedSig = crypto.createHmac('sha256', SECRET_KEY)
      .update(payload)
      .digest('hex');

    if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expectedSig))) {
      return { valid: false, reason: 'Invalid signature' };
    }

    const data = JSON.parse(payload);
    if (data.userId !== userId || data.step !== expectedStep) {
      return { valid: false, reason: 'Step mismatch' };
    }

    // Token expires after 30 minutes
    if (Date.now() - data.timestamp > 30 * 60 * 1000) {
      return { valid: false, reason: 'Token expired' };
    }

    return { valid: true, data: data.data };
  } catch (e) {
    return { valid: false, reason: 'Token parsing failed' };
  }
}

// Step 1: Review cart
app.post('/api/checkout/review', (req, res) => {
  const { userId, items } = req.body;

  if (!userId || !Array.isArray(items) || items.length === 0) {
    return res.status(400).json({ error: 'Invalid cart data' });
  }

  const cartData = { items, total: calculateTotal(items) };
  const reviewToken = generateWorkflowToken(userId, 'cart_reviewed', cartData);

  workflowStates[userId] = { step: 'cart_reviewed', cartData };

  res.json({ 
    success: true, 
    total: cartData.total,
    workflowToken: reviewToken 
  });
});

// Step 2: Process payment - requires cart review token
app.post('/api/checkout/payment', (req, res) => {
  const { userId, paymentMethod, workflowToken } = req.body;

  // Verify previous step was completed
  const verification = verifyWorkflowToken(workflowToken, 'cart_reviewed', userId);
  if (!verification.valid) {
    console.log(`[SECURITY] Payment attempt without cart review: ${userId}`);
    return res.status(403).json({ error: 'Invalid workflow state', reason: verification.reason });
  }

  // Process actual payment
  const paymentResult = processPayment(paymentMethod, verification.data.total);
  if (!paymentResult.success) {
    return res.status(402).json({ error: 'Payment failed' });
  }

  // Store verified payment
  completedPayments.set(paymentResult.transactionId, {
    userId,
    amount: verification.data.total,
    timestamp: Date.now(),
    verified: true
  });

  const paymentToken = generateWorkflowToken(userId, 'payment_completed', {
    transactionId: paymentResult.transactionId,
    cartData: verification.data
  });

  workflowStates[userId] = { step: 'payment_completed' };

  res.json({ 
    success: true, 
    transactionId: paymentResult.transactionId,
    workflowToken: paymentToken 
  });
});

// Step 3: Confirm order - requires payment token AND payment verification
app.post('/api/checkout/confirm', (req, res) => {
  const { userId, workflowToken } = req.body;

  // Verify payment step was completed
  const verification = verifyWorkflowToken(workflowToken, 'payment_completed', userId);
  if (!verification.valid) {
    console.log(`[SECURITY] Order confirmation without payment: ${userId}`);
    return res.status(403).json({ error: 'Invalid workflow state' });
  }

  // Double-check payment was actually processed
  const payment = completedPayments.get(verification.data.transactionId);
  if (!payment || payment.userId !== userId || !payment.verified) {
    console.log(`[SECURITY] Unverified transaction ID: ${verification.data.transactionId}`);
    return res.status(403).json({ error: 'Payment not verified' });
  }

  const orderId = generateOrderId();

  // Invalidate used payment to prevent replay
  completedPayments.delete(verification.data.transactionId);

  res.json({ 
    success: true, 
    orderId,
    message: 'Order confirmed!'
  });
});

function calculateTotal(items) {
  return items.reduce((sum, item) => sum + item.price * item.qty, 0);
}

function processPayment(method, amount) {
  // Real implementation would integrate with payment gateway
  return { success: true, transactionId: 'TX' + crypto.randomBytes(8).toString('hex') };
}

function generateOrderId() {
  return 'ORD' + crypto.randomBytes(8).toString('hex');
}

app.listen(3000);
```

**Key Security Controls**:
- **Cryptographic workflow tokens**: Each step generates a signed token required for the next step
- **Server-side state verification**: Payment records are stored and verified server-side
- **Token expiration**: Workflow tokens expire after 30 minutes preventing stale requests
- **One-time use tokens**: Transaction IDs are invalidated after order confirmation
- **Security logging**: Bypass attempts are logged for monitoring

Complex workflows with conditional paths are even more vulnerable to bypass attacks. Attackers can skip approval steps entirely or manipulate order amounts after approval. Here's a production-ready workflow engine with proper state machine validation.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const Redis = require('ioredis');
const app = express();

app.use(express.json());

const redis = new Redis(process.env.REDIS_URL);
const SECRET_KEY = process.env.WORKFLOW_SECRET;
const APPROVAL_THRESHOLD = 1000; // Orders over $1000 need approval

// Workflow state machine definition
const WORKFLOW_DEFINITION = {
  states: {
    'CART_CREATED': {
      allowedTransitions: ['CART_REVIEWED']
    },
    'CART_REVIEWED': {
      allowedTransitions: ['PENDING_APPROVAL', 'PAYMENT_PENDING'],
      condition: (ctx) => ctx.total > APPROVAL_THRESHOLD ? 'PENDING_APPROVAL' : 'PAYMENT_PENDING'
    },
    'PENDING_APPROVAL': {
      allowedTransitions: ['APPROVED', 'REJECTED'],
      requiredRole: 'manager'
    },
    'APPROVED': {
      allowedTransitions: ['PAYMENT_PENDING']
    },
    'REJECTED': {
      allowedTransitions: [],
      terminal: true
    },
    'PAYMENT_PENDING': {
      allowedTransitions: ['PAYMENT_COMPLETED', 'PAYMENT_FAILED']
    },
    'PAYMENT_COMPLETED': {
      allowedTransitions: ['ORDER_CONFIRMED']
    },
    'PAYMENT_FAILED': {
      allowedTransitions: ['PAYMENT_PENDING'],
      maxRetries: 3
    },
    'ORDER_CONFIRMED': {
      allowedTransitions: [],
      terminal: true
    }
  }
};

class SecureWorkflowEngine {
  constructor(redis, secretKey) {
    this.redis = redis;
    this.secretKey = secretKey;
  }

  // Create new workflow instance with immutable snapshot
  async createWorkflow(userId, initialData) {
    const workflowId = crypto.randomUUID();
    const snapshot = this.createSnapshot(initialData);

    const workflow = {
      id: workflowId,
      userId,
      currentState: 'CART_CREATED',
      dataSnapshot: snapshot,
      dataHash: this.hashData(initialData),
      history: [{
        state: 'CART_CREATED',
        timestamp: Date.now(),
        actor: userId
      }],
      createdAt: Date.now(),
      expiresAt: Date.now() + 24 * 60 * 60 * 1000, // 24 hour expiry
      retryCount: 0
    };

    await this.redis.setex(
      `workflow:${workflowId}`,
      86400,
      JSON.stringify(workflow)
    );

    return { workflowId, token: this.generateToken(workflow) };
  }

  // Create cryptographic snapshot of data at workflow start
  createSnapshot(data) {
    const snapshot = JSON.stringify(data);
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv('aes-256-gcm', this.secretKey, iv);
    let encrypted = cipher.update(snapshot, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag();

    return {
      data: encrypted,
      iv: iv.toString('hex'),
      authTag: authTag.toString('hex')
    };
  }

  // Decrypt and verify snapshot hasn't been tampered
  decryptSnapshot(snapshot) {
    const decipher = crypto.createDecipheriv(
      'aes-256-gcm',
      this.secretKey,
      Buffer.from(snapshot.iv, 'hex')
    );
    decipher.setAuthTag(Buffer.from(snapshot.authTag, 'hex'));
    let decrypted = decipher.update(snapshot.data, 'hex', 'utf8');
    decrypted += decipher.final('utf8');
    return JSON.parse(decrypted);
  }

  hashData(data) {
    return crypto.createHmac('sha256', this.secretKey)
      .update(JSON.stringify(data))
      .digest('hex');
  }

  generateToken(workflow) {
    const payload = {
      wid: workflow.id,
      state: workflow.currentState,
      hash: workflow.dataHash,
      exp: workflow.expiresAt
    };
    const signature = crypto.createHmac('sha256', this.secretKey)
      .update(JSON.stringify(payload))
      .digest('hex');
    return Buffer.from(JSON.stringify(payload)).toString('base64') + '.' + signature;
  }

  verifyToken(token) {
    try {
      const [payloadB64, signature] = token.split('.');
      const payload = JSON.parse(Buffer.from(payloadB64, 'base64').toString());

      const expectedSig = crypto.createHmac('sha256', this.secretKey)
        .update(JSON.stringify(payload))
        .digest('hex');

      if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expectedSig))) {
        return { valid: false, reason: 'Invalid signature' };
      }

      if (Date.now() > payload.exp) {
        return { valid: false, reason: 'Workflow expired' };
      }

      return { valid: true, payload };
    } catch (e) {
      return { valid: false, reason: 'Token parsing failed' };
    }
  }

  // Transition workflow state with full validation
  async transition(workflowId, token, targetState, actor, actorRole = 'user') {
    // Verify token
    const tokenVerification = this.verifyToken(token);
    if (!tokenVerification.valid) {
      await this.logSecurityEvent('INVALID_TOKEN', { workflowId, reason: tokenVerification.reason });
      return { success: false, error: 'Invalid workflow token' };
    }

    // Atomic workflow update with locking
    const lockKey = `lock:workflow:${workflowId}`;
    const lock = await this.redis.set(lockKey, '1', 'NX', 'EX', 10);
    if (!lock) {
      return { success: false, error: 'Workflow is being processed' };
    }

    try {
      const workflowData = await this.redis.get(`workflow:${workflowId}`);
      if (!workflowData) {
        return { success: false, error: 'Workflow not found' };
      }

      const workflow = JSON.parse(workflowData);

      // Verify token matches current workflow state
      if (tokenVerification.payload.state !== workflow.currentState) {
        await this.logSecurityEvent('STATE_MISMATCH', {
          workflowId,
          expectedState: workflow.currentState,
          tokenState: tokenVerification.payload.state
        });
        return { success: false, error: 'Workflow state has changed' };
      }

      // Verify data hasn't been tampered
      if (tokenVerification.payload.hash !== workflow.dataHash) {
        await this.logSecurityEvent('DATA_TAMPERING', { workflowId });
        return { success: false, error: 'Data integrity violation' };
      }

      // Validate state transition
      const currentStateDef = WORKFLOW_DEFINITION.states[workflow.currentState];
      if (!currentStateDef.allowedTransitions.includes(targetState)) {
        await this.logSecurityEvent('INVALID_TRANSITION', {
          workflowId,
          from: workflow.currentState,
          to: targetState
        });
        return { success: false, error: 'Invalid state transition' };
      }

      // Check role requirements
      if (currentStateDef.requiredRole && actorRole !== currentStateDef.requiredRole) {
        await this.logSecurityEvent('INSUFFICIENT_ROLE', {
          workflowId,
          requiredRole: currentStateDef.requiredRole,
          actualRole: actorRole
        });
        return { success: false, error: 'Insufficient permissions' };
      }

      // Handle retry limits
      if (workflow.currentState === 'PAYMENT_FAILED') {
        if (workflow.retryCount >= currentStateDef.maxRetries) {
          return { success: false, error: 'Maximum retries exceeded' };
        }
        workflow.retryCount++;
      }

      // Update workflow
      workflow.currentState = targetState;
      workflow.history.push({
        state: targetState,
        timestamp: Date.now(),
        actor,
        actorRole
      });

      await this.redis.setex(
        `workflow:${workflowId}`,
        86400,
        JSON.stringify(workflow)
      );

      // Audit log
      await this.logAuditEvent('STATE_TRANSITION', {
        workflowId,
        from: tokenVerification.payload.state,
        to: targetState,
        actor
      });

      return {
        success: true,
        newState: targetState,
        token: this.generateToken(workflow),
        isTerminal: WORKFLOW_DEFINITION.states[targetState].terminal || false
      };

    } finally {
      await this.redis.del(lockKey);
    }
  }

  // Get original workflow data (prevents amount manipulation)
  async getWorkflowData(workflowId, token) {
    const tokenVerification = this.verifyToken(token);
    if (!tokenVerification.valid) {
      return null;
    }

    const workflowData = await this.redis.get(`workflow:${workflowId}`);
    if (!workflowData) return null;

    const workflow = JSON.parse(workflowData);

    // Return decrypted original data snapshot
    return this.decryptSnapshot(workflow.dataSnapshot);
  }

  async logSecurityEvent(type, data) {
    const event = {
      type,
      data,
      timestamp: new Date().toISOString(),
      severity: 'HIGH'
    };
    console.error(`[SECURITY ALERT] ${JSON.stringify(event)}`);
    await this.redis.lpush('security:events', JSON.stringify(event));
  }

  async logAuditEvent(type, data) {
    const event = { type, data, timestamp: new Date().toISOString() };
    await this.redis.lpush('audit:events', JSON.stringify(event));
  }
}

const workflowEngine = new SecureWorkflowEngine(redis, Buffer.from(SECRET_KEY, 'hex'));

// API Routes
app.post('/api/checkout/start', async (req, res) => {
  const { userId, items } = req.body;
  const total = items.reduce((sum, item) => sum + item.price * item.qty, 0);

  const { workflowId, token } = await workflowEngine.createWorkflow(userId, { items, total });

  res.json({
    workflowId,
    token,
    total,
    requiresApproval: total > APPROVAL_THRESHOLD
  });
});

app.post('/api/checkout/review', async (req, res) => {
  const { workflowId, token, userId } = req.body;

  // Get immutable original data
  const originalData = await workflowEngine.getWorkflowData(workflowId, token);
  const nextState = originalData.total > APPROVAL_THRESHOLD ? 'PENDING_APPROVAL' : 'PAYMENT_PENDING';

  const result = await workflowEngine.transition(workflowId, token, 'CART_REVIEWED', userId);
  if (!result.success) {
    return res.status(403).json({ error: result.error });
  }

  // Auto-transition to next appropriate state
  const finalResult = await workflowEngine.transition(workflowId, result.token, nextState, userId);

  res.json(finalResult);
});

app.post('/api/checkout/approve', async (req, res) => {
  const { workflowId, token, managerId, decision } = req.body;
  const targetState = decision === 'approve' ? 'APPROVED' : 'REJECTED';

  // Manager role verification would come from auth middleware
  const result = await workflowEngine.transition(workflowId, token, targetState, managerId, 'manager');

  if (!result.success) {
    return res.status(403).json({ error: result.error });
  }

  if (decision === 'approve') {
    // Auto-transition to payment pending
    const paymentResult = await workflowEngine.transition(workflowId, result.token, 'PAYMENT_PENDING', managerId, 'manager');
    return res.json(paymentResult);
  }

  res.json(result);
});

app.post('/api/checkout/payment', async (req, res) => {
  const { workflowId, token, userId, paymentMethod } = req.body;

  // Get original amount (cannot be tampered)
  const originalData = await workflowEngine.getWorkflowData(workflowId, token);

  // Process payment with original amount
  const paymentSuccess = await processPaymentGateway(paymentMethod, originalData.total);
  const targetState = paymentSuccess ? 'PAYMENT_COMPLETED' : 'PAYMENT_FAILED';

  const result = await workflowEngine.transition(workflowId, token, targetState, userId);
  res.json(result);
});

app.post('/api/checkout/confirm', async (req, res) => {
  const { workflowId, token, userId } = req.body;

  const result = await workflowEngine.transition(workflowId, token, 'ORDER_CONFIRMED', userId);

  if (result.success) {
    const originalData = await workflowEngine.getWorkflowData(workflowId, token);
    // Create order with verified data
    const orderId = await createOrder(userId, originalData);
    result.orderId = orderId;
  }

  res.json(result);
});

async function processPaymentGateway(method, amount) { return true; }
async function createOrder(userId, data) { return 'ORD' + crypto.randomBytes(8).toString('hex'); }

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Cryptographic State Tokens**: Every state transition requires a signed token from the previous state, preventing step skipping
```javascript
const tokenVerification = this.verifyToken(token);
if (!tokenVerification.valid || tokenVerification.payload.state !== workflow.currentState) {
  return { success: false, error: 'Invalid workflow state' };
}
```

2. **Immutable Data Snapshots**: Order data is encrypted at workflow creation and cannot be modified mid-workflow
```javascript
// Original total always used for payment, regardless of API input
const originalData = await workflowEngine.getWorkflowData(workflowId, token);
await processPaymentGateway(paymentMethod, originalData.total);
```

3. **State Machine Enforcement**: Only defined transitions are allowed, with role-based access control for approval steps
```javascript
if (!currentStateDef.allowedTransitions.includes(targetState)) {
  await this.logSecurityEvent('INVALID_TRANSITION', { from, to: targetState });
  return { success: false, error: 'Invalid state transition' };
}
```

**Additional Protections**:
- **Atomic operations with Redis locks**: Prevents race conditions in concurrent requests
- **Comprehensive audit trail**: Every state change logged with actor, timestamp, and role
- **Security event alerting**: Bypass attempts trigger immediate security alerts
- **Workflow expiration**: Abandoned workflows auto-expire after 24 hours
- **Retry limits**: Failed payment states have maximum retry counts to prevent abuse
- **Data integrity hashing**: HMAC verification ensures workflow data hasn't been tampered

Checkout workflows are a prime target for business logic attacks. A 2023 incident at Booking.com showed how attackers could skip payment steps entirely by directly calling completion endpoints. Let me show you a common vulnerable pattern:

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import java.sql.*;

public class CheckoutController extends HttpServlet {
    private static final String DB_URL = "jdbc:postgresql://localhost/ecommerce";
    private static final String DB_USER = "dbuser";
    private static final String DB_PASS = "password";

    // Step 1: Add items to cart
    protected void doPost(HttpServletRequest req, HttpServletResponse resp) {
        String action = req.getParameter("action");
        HttpSession session = req.getSession();

        if ("add_to_cart".equals(action)) {
            String productId = req.getParameter("productId");
            int quantity = Integer.parseInt(req.getParameter("quantity"));
            addToCart(session, productId, quantity);
        }
        else if ("apply_coupon".equals(action)) {
            String couponCode = req.getParameter("coupon");
            applyCoupon(session, couponCode);
        }
        else if ("complete_order".equals(action)) {
            // VULNERABLE: No validation that payment was actually processed!
            String orderId = (String) session.getAttribute("orderId");
            completeOrder(orderId);  // Directly marks order as complete
            resp.setStatus(200);
        }
    }

    private void completeOrder(String orderId) {
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // Order is completed without verifying payment status
            PreparedStatement stmt = conn.prepareStatement(
                "UPDATE orders SET status = 'COMPLETED', shipped = true WHERE id = ?");
            stmt.setString(1, orderId);
            stmt.executeUpdate();
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}
```

**Attack Payload**:
```bash
# Attacker creates cart and skips directly to order completion
curl -X POST "https://shop.example.com/checkout" \
  -H "Cookie: JSESSIONID=attacker_session" \
  -d "action=add_to_cart&productId=EXPENSIVE_ITEM&quantity=10"

# Skip payment step entirely and complete order
curl -X POST "https://shop.example.com/checkout" \
  -H "Cookie: JSESSIONID=attacker_session" \
  -d "action=complete_order"
```

**Why This Is Dangerous**:
- No enforcement that previous workflow steps were completed
- Payment verification can be bypassed entirely
- Order state transitions are not validated server-side
- Session state can be manipulated by attackers

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.sql.*;
import java.util.*;
import java.time.Instant;

public class SecureCheckoutController extends HttpServlet {
    private static final String DB_URL = "jdbc:postgresql://localhost/ecommerce";
    private static final String DB_USER = "dbuser";
    private static final String DB_PASS = "password";

    // Define valid workflow states and transitions
    private static final Map<OrderState, Set<OrderState>> VALID_TRANSITIONS = Map.of(
        OrderState.CART, Set.of(OrderState.CHECKOUT_STARTED),
        OrderState.CHECKOUT_STARTED, Set.of(OrderState.PAYMENT_PENDING, OrderState.CART),
        OrderState.PAYMENT_PENDING, Set.of(OrderState.PAYMENT_VERIFIED, OrderState.PAYMENT_FAILED),
        OrderState.PAYMENT_VERIFIED, Set.of(OrderState.ORDER_COMPLETED),
        OrderState.PAYMENT_FAILED, Set.of(OrderState.PAYMENT_PENDING, OrderState.CART)
    );

    public enum OrderState {
        CART, CHECKOUT_STARTED, PAYMENT_PENDING, PAYMENT_VERIFIED, PAYMENT_FAILED, ORDER_COMPLETED
    }

    protected void doPost(HttpServletRequest req, HttpServletResponse resp) 
            throws IOException {
        String action = req.getParameter("action");
        HttpSession session = req.getSession();
        String orderId = (String) session.getAttribute("orderId");

        try {
            if ("complete_order".equals(action)) {
                // SECURE: Validate workflow state before completing
                OrderState currentState = getOrderState(orderId);

                if (currentState != OrderState.PAYMENT_VERIFIED) {
                    logSecurityEvent(orderId, "Attempted order completion without payment", req);
                    resp.sendError(HttpServletResponse.SC_FORBIDDEN, 
                        "Payment must be verified before completing order");
                    return;
                }

                // Verify payment with payment gateway (server-side verification)
                if (!verifyPaymentWithGateway(orderId)) {
                    logSecurityEvent(orderId, "Payment gateway verification failed", req);
                    resp.sendError(HttpServletResponse.SC_PAYMENT_REQUIRED, 
                        "Payment verification failed");
                    return;
                }

                // Atomically transition state with validation
                boolean success = transitionState(orderId, OrderState.PAYMENT_VERIFIED, 
                    OrderState.ORDER_COMPLETED);

                if (!success) {
                    resp.sendError(HttpServletResponse.SC_CONFLICT, 
                        "Order state changed unexpectedly");
                    return;
                }

                resp.setStatus(HttpServletResponse.SC_OK);
            }
        } catch (Exception e) {
            logError("Checkout error", e);
            resp.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
        }
    }

    private boolean transitionState(String orderId, OrderState from, OrderState to) 
            throws SQLException {
        // Validate transition is allowed
        if (!VALID_TRANSITIONS.getOrDefault(from, Set.of()).contains(to)) {
            logSecurityEvent(orderId, "Invalid state transition: " + from + " -> " + to, null);
            return false;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            conn.setAutoCommit(false);

            // Atomic compare-and-swap: only update if current state matches
            PreparedStatement stmt = conn.prepareStatement(
                "UPDATE orders SET status = ?, updated_at = ? " +
                "WHERE id = ? AND status = ?");
            stmt.setString(1, to.name());
            stmt.setTimestamp(2, Timestamp.from(Instant.now()));
            stmt.setString(3, orderId);
            stmt.setString(4, from.name());

            int updated = stmt.executeUpdate();

            if (updated == 1) {
                conn.commit();
                return true;
            } else {
                conn.rollback();
                return false;
            }
        }
    }
}
```

**Key Security Controls**:
- **State machine enforcement**: Only valid state transitions are allowed (PAYMENT_VERIFIED → ORDER_COMPLETED)
- **Server-side payment verification**: Always verify with payment gateway, never trust client claims
- **Atomic state transitions**: Compare-and-swap prevents race conditions in state changes
- **Security event logging**: Attempted bypasses are logged for monitoring

Multiple checkout flows dramatically increase attack surface. Each flow needs its own validated state machine, and you need a central enforcement point. Here's a production-ready pattern:

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import java.sql.*;
import java.util.*;
import java.time.Instant;
import java.util.concurrent.ConcurrentHashMap;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class WorkflowEnforcementService {
    private static final Logger logger = LoggerFactory.getLogger(WorkflowEnforcementService.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY");

    private final PaymentGatewayClient paymentGateway;
    private final MetricsCollector metrics;
    private final Map<WorkflowType, WorkflowDefinition> workflows;

    public enum WorkflowType {
        STANDARD_CHECKOUT,
        GUEST_CHECKOUT,
        EXPRESS_CHECKOUT,
        SUBSCRIPTION_RENEWAL
    }

    public enum CheckoutState {
        INITIALIZED,
        CART_VALIDATED,
        SHIPPING_SELECTED,
        PAYMENT_INITIATED,
        PAYMENT_AUTHORIZED,
        PAYMENT_CAPTURED,
        ORDER_CONFIRMED,
        FULFILLMENT_STARTED
    }

    public WorkflowEnforcementService(PaymentGatewayClient paymentGateway, 
                                       MetricsCollector metrics) {
        this.paymentGateway = paymentGateway;
        this.metrics = metrics;
        this.workflows = initializeWorkflows();
    }

    private Map<WorkflowType, WorkflowDefinition> initializeWorkflows() {
        Map<WorkflowType, WorkflowDefinition> defs = new EnumMap<>(WorkflowType.class);

        // Standard checkout: full flow with shipping
        defs.put(WorkflowType.STANDARD_CHECKOUT, new WorkflowDefinition(
            List.of(
                CheckoutState.INITIALIZED,
                CheckoutState.CART_VALIDATED,
                CheckoutState.SHIPPING_SELECTED,
                CheckoutState.PAYMENT_INITIATED,
                CheckoutState.PAYMENT_AUTHORIZED,
                CheckoutState.PAYMENT_CAPTURED,
                CheckoutState.ORDER_CONFIRMED
            ),
            Map.of(
                CheckoutState.CART_VALIDATED, this::validateCart,
                CheckoutState.PAYMENT_AUTHORIZED, this::verifyPaymentAuthorization,
                CheckoutState.PAYMENT_CAPTURED, this::verifyPaymentCapture
            )
        ));

        // Guest checkout: no account, requires email verification
        defs.put(WorkflowType.GUEST_CHECKOUT, new WorkflowDefinition(
            List.of(
                CheckoutState.INITIALIZED,
                CheckoutState.CART_VALIDATED,
                CheckoutState.SHIPPING_SELECTED,
                CheckoutState.PAYMENT_INITIATED,
                CheckoutState.PAYMENT_CAPTURED,  // Direct capture, no auth hold
                CheckoutState.ORDER_CONFIRMED
            ),
            Map.of(
                CheckoutState.CART_VALIDATED, this::validateCartAndEmail,
                CheckoutState.PAYMENT_CAPTURED, this::verifyPaymentCapture
            )
        ));

        // Express checkout: saved payment method
        defs.put(WorkflowType.EXPRESS_CHECKOUT, new WorkflowDefinition(
            List.of(
                CheckoutState.INITIALIZED,
                CheckoutState.CART_VALIDATED,
                CheckoutState.PAYMENT_CAPTURED,
                CheckoutState.ORDER_CONFIRMED
            ),
            Map.of(
                CheckoutState.CART_VALIDATED, this::validateCartAndSavedPayment,
                CheckoutState.PAYMENT_CAPTURED, this::verifySavedPaymentCapture
            )
        ));

        // Subscription renewal: automated, requires active subscription
        defs.put(WorkflowType.SUBSCRIPTION_RENEWAL, new WorkflowDefinition(
            List.of(
                CheckoutState.INITIALIZED,
                CheckoutState.PAYMENT_CAPTURED,
                CheckoutState.ORDER_CONFIRMED
            ),
            Map.of(
                CheckoutState.INITIALIZED, this::validateActiveSubscription,
                CheckoutState.PAYMENT_CAPTURED, this::verifySubscriptionPayment
            )
        ));

        return Collections.unmodifiableMap(defs);
    }

    /**
     * Central enforcement point for all workflow transitions
     */
    public TransitionResult attemptTransition(String orderId, WorkflowType type, 
                                               CheckoutState targetState, 
                                               TransitionContext context) {
        long startTime = System.currentTimeMillis();

        try {
            // Get workflow definition
            WorkflowDefinition workflow = workflows.get(type);
            if (workflow == null) {
                securityLogger.warn("Unknown workflow type attempted: {} for order {}", 
                    type, orderId);
                return TransitionResult.failure("Invalid workflow type");
            }

            // Load current order state from database
            OrderRecord order = loadOrderWithLock(orderId);
            if (order == null) {
                return TransitionResult.failure("Order not found");
            }

            // Verify workflow type matches order
            if (order.getWorkflowType() != type) {
                securityLogger.error(
                    "SECURITY: Workflow type mismatch. Order {} has type {} but {} attempted. IP: {}",
                    orderId, order.getWorkflowType(), type, context.getClientIp());
                metrics.increment("security.workflow.type_mismatch");
                return TransitionResult.failure("Workflow type mismatch");
            }

            CheckoutState currentState = order.getCurrentState();

            // Validate transition is allowed in this workflow
            if (!workflow.isValidTransition(currentState, targetState)) {
                securityLogger.error(
                    "SECURITY: Invalid transition {} -> {} for workflow {} on order {}. IP: {}",
                    currentState, targetState, type, orderId, context.getClientIp());
                metrics.increment("security.workflow.invalid_transition");
                return TransitionResult.failure("Invalid state transition");
            }

            // Execute pre-transition validation hooks
            ValidationHook hook = workflow.getValidationHook(targetState);
            if (hook != null) {
                ValidationResult validation = hook.validate(order, context);
                if (!validation.isValid()) {
                    logger.info("Transition validation failed for order {}: {}", 
                        orderId, validation.getReason());
                    return TransitionResult.failure(validation.getReason());
                }
            }

            // Perform atomic state transition
            boolean success = atomicStateTransition(orderId, currentState, targetState, type);

            if (success) {
                logger.info("Order {} transitioned {} -> {} in workflow {}", 
                    orderId, currentState, targetState, type);
                metrics.recordTiming("checkout.transition.success", 
                    System.currentTimeMillis() - startTime);

                // Audit log for compliance
                auditLog(orderId, currentState, targetState, context);

                return TransitionResult.success();
            } else {
                // Concurrent modification detected
                logger.warn("Concurrent modification detected for order {}", orderId);
                metrics.increment("checkout.transition.concurrent_conflict");
                return TransitionResult.failure("Order state changed, please retry");
            }

        } catch (Exception e) {
            logger.error("Transition error for order {}", orderId, e);
            metrics.increment("checkout.transition.error");
            return TransitionResult.failure("Internal error");
        }
    }

    private boolean atomicStateTransition(String orderId, CheckoutState from, 
                                          CheckoutState to, WorkflowType type) 
            throws SQLException {
        String sql = 
            "UPDATE orders SET " +
            "  current_state = ?, " +
            "  state_history = state_history || ?::jsonb, " +
            "  updated_at = NOW(), " +
            "  version = version + 1 " +
            "WHERE id = ? AND current_state = ? AND workflow_type = ?";

        try (Connection conn = getConnection()) {
            conn.setTransactionIsolation(Connection.TRANSACTION_SERIALIZABLE);
            conn.setAutoCommit(false);

            try (PreparedStatement stmt = conn.prepareStatement(sql)) {
                stmt.setString(1, to.name());
                stmt.setString(2, buildStateHistoryEntry(from, to));
                stmt.setString(3, orderId);
                stmt.setString(4, from.name());
                stmt.setString(5, type.name());

                int updated = stmt.executeUpdate();

                if (updated == 1) {
                    conn.commit();
                    return true;
                } else {
                    conn.rollback();
                    return false;
                }
            } catch (SQLException e) {
                conn.rollback();
                throw e;
            }
        }
    }

    // Payment verification hooks - always server-side
    private ValidationResult verifyPaymentAuthorization(OrderRecord order, 
                                                        TransitionContext ctx) {
        PaymentAuthResult auth = paymentGateway.verifyAuthorization(
            order.getPaymentIntentId(),
            order.getExpectedAmount(),
            order.getCurrency()
        );

        if (!auth.isAuthorized()) {
            securityLogger.warn("Payment auth verification failed for order {}: {}",
                order.getId(), auth.getFailureReason());
            return ValidationResult.invalid("Payment authorization not verified");
        }

        // Verify amount matches to prevent partial payment attacks
        if (!auth.getAuthorizedAmount().equals(order.getExpectedAmount())) {
            securityLogger.error(
                "SECURITY: Amount mismatch. Order {} expected {} but auth was {}. IP: {}",
                order.getId(), order.getExpectedAmount(), auth.getAuthorizedAmount(), 
                ctx.getClientIp());
            return ValidationResult.invalid("Payment amount mismatch");
        }

        return ValidationResult.valid();
    }

    private ValidationResult verifyPaymentCapture(OrderRecord order, 
                                                  TransitionContext ctx) {
        PaymentCaptureResult capture = paymentGateway.verifyCaptureStatus(
            order.getPaymentIntentId()
        );

        if (capture.getStatus() != CaptureStatus.SUCCEEDED) {
            logger.warn("Payment capture not complete for order {}: {}",
                order.getId(), capture.getStatus());
            return ValidationResult.invalid("Payment not captured");
        }

        return ValidationResult.valid();
    }

    private void auditLog(String orderId, CheckoutState from, CheckoutState to,
                         TransitionContext ctx) {
        // Immutable audit log for compliance (PCI-DSS, SOX)
        String auditEntry = String.format(
            "{\"timestamp\":\"%s\",\"orderId\":\"%s\",\"from\":\"%s\"," +
            "\"to\":\"%s\",\"ip\":\"%s\",\"userId\":\"%s\"}",
            Instant.now(), orderId, from, to, ctx.getClientIp(), ctx.getUserId()
        );

        // Write to append-only audit table
        writeAuditLog(auditEntry);
    }
}

// Supporting classes
class WorkflowDefinition {
    private final List<CheckoutState> orderedStates;
    private final Map<CheckoutState, ValidationHook> validationHooks;

    public WorkflowDefinition(List<CheckoutState> states, 
                              Map<CheckoutState, ValidationHook> hooks) {
        this.orderedStates = List.copyOf(states);
        this.validationHooks = Map.copyOf(hooks);
    }

    public boolean isValidTransition(CheckoutState from, CheckoutState to) {
        int fromIndex = orderedStates.indexOf(from);
        int toIndex = orderedStates.indexOf(to);

        // Only allow forward progression by exactly one step
        return fromIndex >= 0 && toIndex == fromIndex + 1;
    }

    public ValidationHook getValidationHook(CheckoutState state) {
        return validationHooks.get(state);
    }
}

@FunctionalInterface
interface ValidationHook {
    ValidationResult validate(OrderRecord order, TransitionContext context);
}
```

**Defense in Depth Layers**:

1. **Workflow Definition Layer**: Each checkout type has explicitly defined valid states and transitions
```java
// Only these transitions are valid - everything else is rejected
STANDARD: INIT -> CART -> SHIPPING -> PAYMENT_INIT -> AUTH -> CAPTURE -> CONFIRM
GUEST:    INIT -> CART -> SHIPPING -> PAYMENT_INIT -> CAPTURE -> CONFIRM
EXPRESS:  INIT -> CART -> CAPTURE -> CONFIRM
```

2. **Server-Side Verification Layer**: All payment states verified with payment gateway
```java
// Never trust client claims about payment status
PaymentCaptureResult capture = paymentGateway.verifyCaptureStatus(paymentIntentId);
if (capture.getStatus() != CaptureStatus.SUCCEEDED) {
    return ValidationResult.invalid("Payment not captured");
}
```

3. **Atomic Database Layer**: Compare-and-swap prevents race conditions
```java
// Only updates if current state matches expected state
"UPDATE orders SET current_state = ? WHERE id = ? AND current_state = ?"
```

**Additional Protections**:

- **Workflow type immutability**: Order workflow type is set at creation and cannot be changed, preventing attackers from switching to a simpler flow
- **Amount verification**: Payment amounts verified server-side to prevent partial payment attacks
- **Comprehensive audit trail**: Every state transition logged with timestamp, IP, user for forensics and compliance
- **Security-specific logging**: Suspicious activity (invalid transitions, type mismatches) logged to separate security channel for SIEM integration
- **Metrics collection**: Real-time monitoring of workflow anomalies enables rapid incident response
- **Serializable transactions**: Highest isolation level prevents race condition exploits

This is a critical security question! Many applications suffer from insufficient workflow validation, allowing attackers to skip steps or manipulate state. The 2023 Retool breach showed how skipping workflow steps can lead to complete authentication bypass.

**VULNERABLE CODE**:

