**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { createClient } = require('redis');
const crypto = require('crypto');

const app = express();
const redis = createClient();

// Workflow configuration for different checkout types
const CHECKOUT_WORKFLOWS = {
  standard: {
    steps: ['cart', 'address', 'payment_method', 'review', 'payment', 'fraud_check', 'complete'],
    required_validations: ['address_verified', 'payment_captured', 'fraud_cleared'],
    timeout_minutes: 30
  },
  express: {
    steps: ['cart', 'saved_address_confirm', 'saved_payment_confirm', 'payment', 'fraud_check', 'complete'],
    required_validations: ['saved_address_valid', 'payment_captured', 'fraud_cleared'],
    timeout_minutes: 15,
    requires_authenticated_user: true
  },
  guest: {
    steps: ['cart', 'email', 'address', 'payment_method', 'review', 'payment', 'fraud_check', 'complete'],
    required_validations: ['email_verified', 'address_verified', 'payment_captured', 'fraud_cleared', 'captcha_passed'],
    timeout_minutes: 45
  },
  subscription: {
    steps: ['plan_select', 'account', 'payment_method', 'terms_accept', 'payment', 'fraud_check', 'complete'],
    required_validations: ['account_created', 'terms_accepted', 'payment_captured', 'fraud_cleared'],
    timeout_minutes: 60
  }
};

class WorkflowStateMachine {
  constructor(orderId, checkoutType, userId = null) {
    this.orderId = orderId;
    this.checkoutType = checkoutType;
    this.userId = userId;
    this.workflow = CHECKOUT_WORKFLOWS[checkoutType];
    this.stateKey = `workflow:${orderId}`;
  }

  async initialize() {
    // Generate cryptographic workflow token to prevent tampering
    const workflowToken = crypto.randomBytes(32).toString('hex');

    const state = {
      orderId: this.orderId,
      checkoutType: this.checkoutType,
      userId: this.userId,
      workflowToken: workflowToken,
      currentStep: 0,
      completedSteps: [],
      validations: {},
      startedAt: Date.now(),
      expiresAt: Date.now() + (this.workflow.timeout_minutes * 60 * 1000),
      ipAddress: null,
      userAgent: null
    };

    await redis.set(this.stateKey, JSON.stringify(state), {
      EX: this.workflow.timeout_minutes * 60
    });

    return { workflowToken, firstStep: this.workflow.steps[0] };
  }

  async getState() {
    const stateJson = await redis.get(this.stateKey);
    if (!stateJson) return null;
    return JSON.parse(stateJson);
  }

  async validateAndAdvance(stepName, workflowToken, validationData = {}) {
    const state = await this.getState();

    if (!state) {
      return { success: false, error: 'WORKFLOW_EXPIRED', code: 'WF001' };
    }

    // Verify workflow token matches (prevents session hijacking)
    if (state.workflowToken !== workflowToken) {
      console.error(`Workflow token mismatch for order ${this.orderId}`);
      return { success: false, error: 'INVALID_WORKFLOW_TOKEN', code: 'WF002' };
    }

    // Check workflow hasn't expired
    if (Date.now() > state.expiresAt) {
      await this.invalidate('TIMEOUT');
      return { success: false, error: 'WORKFLOW_TIMEOUT', code: 'WF003' };
    }

    // Validate step is the expected next step
    const expectedStep = this.workflow.steps[state.currentStep];
    if (stepName !== expectedStep) {
      console.warn(`Workflow sequence violation: expected ${expectedStep}, got ${stepName}`);
      return { 
        success: false, 
        error: 'INVALID_STEP_SEQUENCE',
        expected: expectedStep,
        received: stepName,
        code: 'WF004'
      };
    }

    // Record step completion with timestamp
    state.completedSteps.push({
      step: stepName,
      completedAt: Date.now(),
      data: this.sanitizeValidationData(validationData)
    });

    // Record any validations that passed
    if (validationData.validations) {
      for (const [key, value] of Object.entries(validationData.validations)) {
        state.validations[key] = {
          passed: value,
          timestamp: Date.now()
        };
      }
    }

    state.currentStep++;
    await redis.set(this.stateKey, JSON.stringify(state), {
      EX: Math.ceil((state.expiresAt - Date.now()) / 1000)
    });

    const nextStep = this.workflow.steps[state.currentStep] || null;
    return { success: true, nextStep, currentStep: state.currentStep };
  }

  async canComplete() {
    const state = await this.getState();
    if (!state) return { canComplete: false, reason: 'WORKFLOW_NOT_FOUND' };

    // Check all required validations passed
    const missingValidations = [];
    for (const required of this.workflow.required_validations) {
      if (!state.validations[required]?.passed) {
        missingValidations.push(required);
      }
    }

    if (missingValidations.length > 0) {
      return {
        canComplete: false,
        reason: 'MISSING_VALIDATIONS',
        missing: missingValidations
      };
    }

    // Verify we're at the final step
    const finalStep = this.workflow.steps[this.workflow.steps.length - 1];
    const currentStepName = this.workflow.steps[state.currentStep];
    if (currentStepName !== finalStep) {
      return {
        canComplete: false,
        reason: 'WORKFLOW_INCOMPLETE',
        currentStep: currentStepName,
        requiredStep: finalStep
      };
    }

    return { canComplete: true };
  }

  async invalidate(reason) {
    const state = await this.getState();
    if (state) {
      // Log invalidation for audit
      await db.query(
        `INSERT INTO workflow_audit_log (order_id, action, reason, state_snapshot, created_at)
         VALUES ($1, $2, $3, $4, NOW())`,
        [this.orderId, 'INVALIDATED', reason, JSON.stringify(state)]
      );
    }
    await redis.del(this.stateKey);
  }

  sanitizeValidationData(data) {
    // Remove sensitive data before storing
    const sanitized = { ...data };
    delete sanitized.cardNumber;
    delete sanitized.cvv;
    delete sanitized.password;
    return sanitized;
  }
}

// Middleware to enforce workflow validation
const requireWorkflowStep = (stepName) => {
  return async (req, res, next) => {
    const { orderId } = req.params;
    const workflowToken = req.headers['x-workflow-token'];
    const checkoutType = req.headers['x-checkout-type'] || 'standard';

    if (!workflowToken) {
      return res.status(400).json({ error: 'Missing workflow token' });
    }

    const workflow = new WorkflowStateMachine(orderId, checkoutType, req.session?.userId);
    const result = await workflow.validateAndAdvance(stepName, workflowToken, req.body);

    if (!result.success) {
      // Log security event
      console.warn(`Workflow violation: ${JSON.stringify(result)}, IP: ${req.ip}`);
      return res.status(400).json(result);
    }

    req.workflow = workflow;
    req.workflowState = result;
    next();
  };
};

// API Routes with workflow enforcement
