  const { checkoutType = 'standard' } = req.body;
  const userId = req.session?.userId;

  // Validate checkout type requires auth
  if (CHECKOUT_WORKFLOWS[checkoutType]?.requires_authenticated_user && !userId) {
    return res.status(401).json({ error: 'Authentication required for this checkout type' });
  }

  // Create order in pending state
  const order = await db.query(
    `INSERT INTO orders (user_id, checkout_type, status, created_at)
     VALUES ($1, $2, 'pending', NOW()) RETURNING id`,
    [userId, checkoutType]
  );

  const orderId = order.rows[0].id;
  const workflow = new WorkflowStateMachine(orderId, checkoutType, userId);
  const { workflowToken, firstStep } = await workflow.initialize();

  res.json({
    orderId,
    workflowToken,
    nextStep: firstStep,
    expiresIn: CHECKOUT_WORKFLOWS[checkoutType].timeout_minutes * 60
  });
});

app.post('/api/checkout/:orderId/payment',
  requireWorkflowStep('payment'),
  async (req, res) => {
    const { orderId } = req.params;
    const { paymentMethodId } = req.body;

    // Process payment with external provider
    const paymentResult = await paymentProcessor.charge({
      orderId,
