    });

    if (paymentResult.success) {
      // Record validation
      await req.workflow.validateAndAdvance('payment', req.headers['x-workflow-token'], {
        validations: { payment_captured: true }
      });

      res.json({
        success: true,
        transactionId: paymentResult.transactionId,
        nextStep: req.workflowState.nextStep
      });
    } else {
      res.status(400).json({ error: 'Payment failed', details: paymentResult.error });
    }
  }
);

app.post('/api/checkout/:orderId/complete',
  requireWorkflowStep('complete'),
  async (req, res) => {
    const { orderId } = req.params;

    // Final validation check
    const completionCheck = await req.workflow.canComplete();
    if (!completionCheck.canComplete) {
      console.error(`Completion blocked for order ${orderId}: ${completionCheck.reason}`);
      return res.status(400).json(completionCheck);
    }

    // Atomic order completion with transaction
    const client = await db.pool.connect();
    try {
      await client.query('BEGIN');

      // Lock and update order
      await client.query(
        `UPDATE orders SET status = 'completed', completed_at = NOW()
         WHERE id = $1 AND status = 'pending'`,
        [orderId]
      );

      // Create audit record
      await client.query(
        `INSERT INTO order_completion_audit (order_id, workflow_state, completed_at)
         VALUES ($1, $2, NOW())`,
        [orderId, JSON.stringify(await req.workflow.getState())]
      );

      await client.query('COMMIT');

      // Cleanup workflow state
      await req.workflow.invalidate('COMPLETED');

      // Trigger post-completion actions
      await shippingService.scheduleDelivery(orderId);
      await notificationService.sendOrderConfirmation(orderId);

      res.json({ success: true, orderId });
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }
);

