Multi-step workflows require careful state management to prevent users from bypassing required steps. A common vulnerability is allowing direct access to any step without validating the user completed previous steps.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/json"
	"net/http"
	"sync"
)

type Order struct {
	ID          string  `json:"id"`
	Items       []Item  `json:"items"`
	ShippingAddr string  `json:"shipping_addr"`
	Total       float64 `json:"total"`
	Paid        bool    `json:"paid"`
}

type Item struct {
	ProductID string  `json:"product_id"`
	Quantity  int     `json:"quantity"`
	Price     float64 `json:"price"`
}

var orders = make(map[string]*Order)
var mu sync.RWMutex

// VULNERABLE: No workflow state validation
func addShipping(w http.ResponseWriter, r *http.Request) {
	orderID := r.URL.Query().Get("order_id")
	var req struct {
		Address string `json:"address"`
	}
	json.NewDecoder(r.Body).Decode(&req)

	mu.Lock()
	if order, exists := orders[orderID]; exists {
		// No check if items were added first!
		order.ShippingAddr = req.Address
	}
	mu.Unlock()
	w.WriteHeader(http.StatusOK)
}

// VULNERABLE: Can process payment without completing prior steps
func processPayment(w http.ResponseWriter, r *http.Request) {
	orderID := r.URL.Query().Get("order_id")
	var req struct {
		Amount float64 `json:"amount"`
	}
	json.NewDecoder(r.Body).Decode(&req)

	mu.Lock()
	if order, exists := orders[orderID]; exists {
		// No validation of workflow state!
		// Attacker can pay $0 for items they never added
		order.Paid = true
		order.Total = req.Amount // User controls the amount!
	}
	mu.Unlock()
	w.WriteHeader(http.StatusOK)
}
```

**Attack Payload**:
```bash
# Step 1: Create empty order
curl -X POST http://localhost:8080/order/create
# Returns: {"id": "order-123"}

# Step 2: Skip item addition and shipping, go directly to payment with $0
curl -X POST "http://localhost:8080/order/pay?order_id=order-123" \
  -H "Content-Type: application/json" \
  -d '{"amount": 0.00}'

# Order is now marked as paid with $0 total!
```

**Why This Is Dangerous**:
- Attackers can skip mandatory steps like adding items or shipping address
- Payment amount is user-controlled, allowing $0 purchases
- No validation that workflow state transitions are valid
- Business logic bypass leads to financial fraud

**SECURE VERSION**:

```go
package main

import (
	"encoding/json"
	"errors"
	"log"
	"net/http"
	"sync"
	"time"
)

type WorkflowState string

const (
	StateCreated        WorkflowState = "created"
	StateItemsAdded     WorkflowState = "items_added"
	StateShippingAdded  WorkflowState = "shipping_added"
	StatePendingPayment WorkflowState = "pending_payment"
	StatePaid           WorkflowState = "paid"
	StateCompleted      WorkflowState = "completed"
)

// Define valid state transitions
var validTransitions = map[WorkflowState][]WorkflowState{
	StateCreated:        {StateItemsAdded},
	StateItemsAdded:     {StateShippingAdded},
	StateShippingAdded:  {StatePendingPayment},
	StatePendingPayment: {StatePaid},
	StatePaid:           {StateCompleted},
}

type SecureOrder struct {
	ID           string        `json:"id"`
	Items        []Item        `json:"items"`
	ShippingAddr string        `json:"shipping_addr"`
	Total        float64       `json:"total"`
	State        WorkflowState `json:"state"`
	CreatedAt    time.Time     `json:"created_at"`
	UpdatedAt    time.Time     `json:"updated_at"`
	StateHistory []StateChange `json:"state_history"`
}

type StateChange struct {
	From      WorkflowState `json:"from"`
	To        WorkflowState `json:"to"`
	Timestamp time.Time     `json:"timestamp"`
	UserID    string        `json:"user_id"`
}

var secureOrders = make(map[string]*SecureOrder)
var orderMu sync.RWMutex

// Validate state transition is allowed
func (o *SecureOrder) canTransitionTo(newState WorkflowState) bool {
	allowedStates, exists := validTransitions[o.State]
	if !exists {
		return false
	}
	for _, allowed := range allowedStates {
		if allowed == newState {
			return true
		}
	}
	return false
}

// Safe state transition with audit logging
func (o *SecureOrder) transitionTo(newState WorkflowState, userID string) error {
	if !o.canTransitionTo(newState) {
		log.Printf("SECURITY: Invalid state transition attempt from %s to %s for order %s by user %s",
			o.State, newState, o.ID, userID)
		return errors.New("invalid workflow transition")
	}

	o.StateHistory = append(o.StateHistory, StateChange{
		From:      o.State,
		To:        newState,
		Timestamp: time.Now(),
		UserID:    userID,
	})
	o.State = newState
	o.UpdatedAt = time.Now()
	return nil
}

// SECURE: Validates workflow state before shipping
func addShippingSecure(w http.ResponseWriter, r *http.Request) {
	orderID := r.URL.Query().Get("order_id")
	userID := r.Header.Get("X-User-ID") // From authenticated session

	var req struct {
		Address string `json:"address"`
	}
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	orderMu.Lock()
	defer orderMu.Unlock()

	order, exists := secureOrders[orderID]
	if !exists {
		http.Error(w, "Order not found", http.StatusNotFound)
		return
	}

	// SECURITY: Validate current state allows shipping addition
	if order.State != StateItemsAdded {
		log.Printf("SECURITY: Workflow bypass attempt on order %s, current state: %s", orderID, order.State)
		http.Error(w, "Items must be added before shipping", http.StatusForbidden)
		return
	}

	order.ShippingAddr = req.Address
	if err := order.transitionTo(StateShippingAdded, userID); err != nil {
		http.Error(w, err.Error(), http.StatusForbidden)
		return
	}

	w.WriteHeader(http.StatusOK)
}
```

**Key Security Controls**:
- **State machine enforcement**: Only valid transitions are allowed (created → items_added → shipping_added → etc.)
- **Server-side total calculation**: Payment amount is calculated from items, not user input
- **Audit logging**: All state transitions are logged with user ID and timestamp
- **Fail-closed design**: Invalid transitions return errors, not silent success

Complex workflows with conditional branches and role-based approvals require a robust state machine with authorization checks at each transition. Here's a production-ready pattern:

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"net/http"
	"sync"
	"time"
)

// Workflow states for approval process
type ApprovalState string

const (
	StateDraft             ApprovalState = "draft"
	StatePendingReview     ApprovalState = "pending_review"
	StatePendingManagerApp ApprovalState = "pending_manager_approval"
	StatePendingFinanceApp ApprovalState = "pending_finance_approval"
	StatePendingLegalApp   ApprovalState = "pending_legal_approval"
	StateApproved          ApprovalState = "approved"
	StateRejected          ApprovalState = "rejected"
	StateCancelled         ApprovalState = "cancelled"
)

// Role-based permissions
type Role string

const (
	RoleSubmitter Role = "submitter"
	RoleReviewer  Role = "reviewer"
	RoleManager   Role = "manager"
	RoleFinance   Role = "finance"
	RoleLegal     Role = "legal"
	RoleAdmin     Role = "admin"
)

// Transition definition with conditions
type Transition struct {
	From            ApprovalState
	To              ApprovalState
	AllowedRoles    []Role
	Condition       func(*ApprovalRequest) bool
	RequiresComment bool
}

// Approval request structure
type ApprovalRequest struct {
	ID             string            `json:"id"`
	Title          string            `json:"title"`
	Amount         float64           `json:"amount"`
	Department     string            `json:"department"`
	State          ApprovalState     `json:"state"`
	SubmitterID    string            `json:"submitter_id"`
	Approvals      []ApprovalRecord  `json:"approvals"`
	StateHistory   []StateTransition `json:"state_history"`
	CreatedAt      time.Time         `json:"created_at"`
	UpdatedAt      time.Time         `json:"updated_at"`
	ExpiresAt      time.Time         `json:"expires_at"`
}

type ApprovalRecord struct {
	Role       Role      `json:"role"`
	UserID     string    `json:"user_id"`
	Action     string    `json:"action"`
	Comment    string    `json:"comment"`
	Timestamp  time.Time `json:"timestamp"`
	IPAddress  string    `json:"ip_address"`
}

type StateTransition struct {
	From        ApprovalState `json:"from"`
	To          ApprovalState `json:"to"`
	TriggeredBy string        `json:"triggered_by"`
	Reason      string        `json:"reason"`
	Timestamp   time.Time     `json:"timestamp"`
}

type User struct {
	ID    string
	Roles []Role
}

// Workflow engine with configurable transitions
type WorkflowEngine struct {
	transitions []Transition
	requests    map[string]*ApprovalRequest
	mu          sync.RWMutex
	notifier    NotificationService
	auditLog    AuditLogger
}

type NotificationService interface {
	Notify(ctx context.Context, userIDs []string, message string) error
}

type AuditLogger interface {
	LogTransition(ctx context.Context, requestID string, transition StateTransition) error
	LogSecurityEvent(ctx context.Context, event SecurityEvent) error
}

type SecurityEvent struct {
	Type      string    `json:"type"`
	UserID    string    `json:"user_id"`
	RequestID string    `json:"request_id"`
	Details   string    `json:"details"`
	IPAddress string    `json:"ip_address"`
	Timestamp time.Time `json:"timestamp"`
}

func NewWorkflowEngine(notifier NotificationService, auditLog AuditLogger) *WorkflowEngine {
	engine := &WorkflowEngine{
		requests: make(map[string]*ApprovalRequest),
		notifier: notifier,
		auditLog: auditLog,
	}

	// Define all valid transitions with role requirements and conditions
	engine.transitions = []Transition{
		// Submit for review
		{
			From:         StateDraft,
			To:           StatePendingReview,
			AllowedRoles: []Role{RoleSubmitter},
			Condition:    func(r *ApprovalRequest) bool { return r.Amount > 0 && r.Title != "" },
		},
		// Reviewer approves - routes based on amount
		{
			From:            StatePendingReview,
			To:              StatePendingManagerApp,
			AllowedRoles:    []Role{RoleReviewer},
			Condition:       func(r *ApprovalRequest) bool { return r.Amount < 10000 },
			RequiresComment: true,
		},
		{
			From:            StatePendingReview,
			To:              StatePendingFinanceApp,
			AllowedRoles:    []Role{RoleReviewer},
			Condition:       func(r *ApprovalRequest) bool { return r.Amount >= 10000 },
			RequiresComment: true,
		},
		// Finance approval for high-value requests
		{
			From:            StatePendingFinanceApp,
			To:              StatePendingLegalApp,
			AllowedRoles:    []Role{RoleFinance},
			Condition:       func(r *ApprovalRequest) bool { return r.Amount >= 50000 },
			RequiresComment: true,
		},
		{
			From:            StatePendingFinanceApp,
			To:              StatePendingManagerApp,
			AllowedRoles:    []Role{RoleFinance},
			Condition:       func(r *ApprovalRequest) bool { return r.Amount < 50000 },
			RequiresComment: true,
		},
		// Legal approval
		{
			From:            StatePendingLegalApp,
			To:              StatePendingManagerApp,
			AllowedRoles:    []Role{RoleLegal},
			RequiresComment: true,
		},
		// Final manager approval
		{
			From:            StatePendingManagerApp,
			To:              StateApproved,
			AllowedRoles:    []Role{RoleManager},
			RequiresComment: true,
		},
		// Rejection from any pending state
		{
			From:            StatePendingReview,
			To:              StateRejected,
			AllowedRoles:    []Role{RoleReviewer, RoleAdmin},
			RequiresComment: true,
		},
		{
			From:            StatePendingFinanceApp,
			To:              StateRejected,
			AllowedRoles:    []Role{RoleFinance, RoleAdmin},
			RequiresComment: true,
		},
		{
			From:            StatePendingManagerApp,
			To:              StateRejected,
			AllowedRoles:    []Role{RoleManager, RoleAdmin},
			RequiresComment: true,
		},
	}

	return engine
}

// Find valid transition
func (e *WorkflowEngine) findTransition(request *ApprovalRequest, targetState ApprovalState, user *User) (*Transition, error) {
	for _, t := range e.transitions {
		if t.From != request.State || t.To != targetState {
			continue
		}

		// Check role permission
		hasRole := false
		for _, allowedRole := range t.AllowedRoles {
			for _, userRole := range user.Roles {
				if allowedRole == userRole {
					hasRole = true
					break
				}
			}
		}
		if !hasRole {
			continue
		}

		// Check condition if exists
		if t.Condition != nil && !t.Condition(request) {
			continue
		}

		return &t, nil
	}

	return nil, errors.New("no valid transition found")
}

// Execute state transition with full validation
func (e *WorkflowEngine) Transition(ctx context.Context, requestID string, targetState ApprovalState, user *User, comment string, ipAddress string) error {
	e.mu.Lock()
	defer e.mu.Unlock()

	request, exists := e.requests[requestID]
	if !exists {
		return errors.New("request not found")
	}

	// Check request hasn't expired
	if time.Now().After(request.ExpiresAt) {
		e.auditLog.LogSecurityEvent(ctx, SecurityEvent{
			Type:      "expired_request_access",
			UserID:    user.ID,
			RequestID: requestID,
			Details:   "Attempted transition on expired request",
			IPAddress: ipAddress,
			Timestamp: time.Now(),
		})
		return errors.New("request has expired")
	}

	// Find valid transition
	transition, err := e.findTransition(request, targetState, user)
	if err != nil {
		e.auditLog.LogSecurityEvent(ctx, SecurityEvent{
			Type:      "invalid_transition_attempt",
			UserID:    user.ID,
			RequestID: requestID,
			Details:   fmt.Sprintf("From: %s, To: %s", request.State, targetState),
			IPAddress: ipAddress,
			Timestamp: time.Now(),
		})
		return fmt.Errorf("invalid transition: %w", err)
	}

	// Validate comment requirement
	if transition.RequiresComment && comment == "" {
		return errors.New("comment required for this transition")
	}

	// Prevent self-approval
	if request.SubmitterID == user.ID && (targetState == StateApproved || targetState == StatePendingManagerApp) {
		e.auditLog.LogSecurityEvent(ctx, SecurityEvent{
			Type:      "self_approval_attempt",
			UserID:    user.ID,
			RequestID: requestID,
			Details:   "User attempted to approve their own request",
			IPAddress: ipAddress,
			Timestamp: time.Now(),
		})
		return errors.New("cannot approve own request")
	}

	// Record the transition
	stateChange := StateTransition{
		From:        request.State,
		To:          targetState,
		TriggeredBy: user.ID,
		Reason:      comment,
		Timestamp:   time.Now(),
	}

	request.StateHistory = append(request.StateHistory, stateChange)
	request.State = targetState
	request.UpdatedAt = time.Now()

	// Record approval
	request.Approvals = append(request.Approvals, ApprovalRecord{
		Role:      user.Roles[0], // Primary role
		UserID:    user.ID,
		Action:    string(targetState),
		Comment:   comment,
		Timestamp: time.Now(),
		IPAddress: ipAddress,
	})

	// Audit log
	e.auditLog.LogTransition(ctx, requestID, stateChange)

	log.Printf("INFO: Request %s transitioned from %s to %s by user %s",
		requestID, stateChange.From, stateChange.To, user.ID)

	return nil
}

// HTTP Handler with comprehensive validation
func (e *WorkflowEngine) HandleTransition(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()

	// Get authenticated user from context (set by auth middleware)
	user, ok := ctx.Value("user").(*User)
	if !ok {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	var req struct {
		RequestID   string        `json:"request_id"`
		TargetState ApprovalState `json:"target_state"`
		Comment     string        `json:"comment"`
	}

	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request body", http.StatusBadRequest)
		return
	}

	ipAddress := r.Header.Get("X-Forwarded-For")
	if ipAddress == "" {
		ipAddress = r.RemoteAddr
	}

	err := e.Transition(ctx, req.RequestID, req.TargetState, user, req.Comment, ipAddress)
	if err != nil {
		log.Printf("WARN: Transition failed for user %s: %v", user.ID, err)
		http.Error(w, err.Error(), http.StatusForbidden)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"status": "success"})
}
```

