**SECURE VERSION**:

```python
from flask import Flask, session, request, jsonify
from functools import wraps
from enum import Enum, auto
from datetime import datetime, timedelta
import uuid
import hashlib
import hmac
import logging

app = Flask(__name__)
app.secret_key = 'secure-random-secret-key-from-env'
logging.basicConfig(level=logging.INFO)

class CheckoutState(Enum):
    INITIALIZED = auto()
    CART_FILLED = auto()
    SHIPPING_SET = auto()
    PAYMENT_COMPLETE = auto()
    CONFIRMED = auto()

# Define valid state transitions
VALID_TRANSITIONS = {
    None: [CheckoutState.INITIALIZED],
    CheckoutState.INITIALIZED: [CheckoutState.CART_FILLED],
    CheckoutState.CART_FILLED: [CheckoutState.SHIPPING_SET],
    CheckoutState.SHIPPING_SET: [CheckoutState.PAYMENT_COMPLETE],
    CheckoutState.PAYMENT_COMPLETE: [CheckoutState.CONFIRMED],
    CheckoutState.CONFIRMED: []  # Terminal state
}

def generate_state_token(order_id, state, secret):
    """Generate cryptographic token to prevent state tampering"""
    message = f"{order_id}:{state.name}:{datetime.utcnow().strftime('%Y%m%d%H')}"
    return hmac.new(secret.encode(), message.encode(), hashlib.sha256).hexdigest()

def validate_workflow_state(required_state):
    """Decorator to enforce workflow state requirements"""
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            current_state_name = session.get('checkout_state')
            current_state = CheckoutState[current_state_name] if current_state_name else None

            # Verify state token to prevent tampering
            stored_token = session.get('state_token')
            if current_state:
                expected_token = generate_state_token(
                    session.get('order_id'), 
                    current_state,
                    app.secret_key
                )
                if not hmac.compare_digest(stored_token or '', expected_token):
                    logging.warning(f"State tampering detected for order {session.get('order_id')}")
                    return jsonify({'error': 'Invalid session state'}), 403

            # Validate state transition
            if required_state not in VALID_TRANSITIONS.get(current_state, []):
                logging.warning(
                    f"Invalid workflow transition: {current_state} -> {required_state} "
                    f"for order {session.get('order_id')}"
                )
                return jsonify({
                    'error': 'Invalid checkout state',
                    'current_state': current_state_name,
                    'required_previous_state': [s.name for s in VALID_TRANSITIONS if required_state in VALID_TRANSITIONS.get(s, [])]
                }), 400

            return f(*args, **kwargs)
        return wrapper
    return decorator

def update_state(new_state):
    """Safely update workflow state with cryptographic token"""
    session['checkout_state'] = new_state.name
    session['state_token'] = generate_state_token(
        session['order_id'],
        new_state,
        app.secret_key
    )
    session['state_timestamp'] = datetime.utcnow().isoformat()

@app.route('/checkout/start', methods=['POST'])
def start_checkout():
    """Initialize checkout workflow"""
    session['order_id'] = str(uuid.uuid4())
    update_state(CheckoutState.INITIALIZED)
    logging.info(f"Checkout started: {session['order_id']}")
    return jsonify({'status': 'checkout_started', 'order_id': session['order_id']})

@app.route('/checkout/cart', methods=['POST'])
@validate_workflow_state(CheckoutState.CART_FILLED)
def add_to_cart():
    """Step 1: Add items to cart - requires INITIALIZED state"""
    session['cart'] = request.json.get('items', [])
    update_state(CheckoutState.CART_FILLED)
    return jsonify({'status': 'cart_updated'})

@app.route('/checkout/shipping', methods=['POST'])
@validate_workflow_state(CheckoutState.SHIPPING_SET)
def set_shipping():
    """Step 2: Set shipping - requires CART_FILLED state"""
    session['shipping'] = request.json.get('address')
    update_state(CheckoutState.SHIPPING_SET)
    return jsonify({'status': 'shipping_set'})

@app.route('/checkout/payment', methods=['POST'])
@validate_workflow_state(CheckoutState.PAYMENT_COMPLETE)
def process_payment():
    """Step 3: Process payment - requires SHIPPING_SET state"""
    payment_result = process_payment_gateway(request.json)
    if payment_result['success']:
        session['payment_id'] = payment_result['transaction_id']
        update_state(CheckoutState.PAYMENT_COMPLETE)
        return jsonify({'status': 'payment_success'})
    return jsonify({'status': 'payment_failed'}), 400

@app.route('/checkout/confirm', methods=['POST'])
@validate_workflow_state(CheckoutState.CONFIRMED)
def confirm_order():
    """Step 4: Confirm order - requires PAYMENT_COMPLETE state"""
    order_id = session['order_id']

    # Double-check payment was actually processed
    if not verify_payment_with_gateway(session.get('payment_id')):
        logging.error(f"Payment verification failed for order {order_id}")
        return jsonify({'error': 'Payment verification failed'}), 400

    update_state(CheckoutState.CONFIRMED)
    logging.info(f"Order confirmed: {order_id}")
    return jsonify({'status': 'order_confirmed', 'order_id': order_id})
```

**Key Security Controls**:
- **State machine enforcement**: Each step validates that the previous step was completed using an enum-based state machine
- **Cryptographic state tokens**: HMAC-signed tokens prevent session tampering and state manipulation
- **Transition validation**: Only valid state transitions are allowed, preventing step skipping
- **Audit logging**: All state changes and violations are logged for security monitoring

