  transitions: {
    'initiated': ['cart_validated'],
    'cart_validated': ['guest_info_collected', 'user_authenticated'],
    'guest_info_collected': ['shipping_selected'],
    'user_authenticated': ['shipping_selected'],
    'shipping_selected': ['card_payment_pending', 'paypal_redirect', 'crypto_payment_pending'],
    'card_payment_pending': ['card_payment_verified', 'order_failed'],
    'card_payment_verified': ['order_confirmed'],
    'paypal_redirect': ['paypal_confirmed', 'order_failed'],
    'paypal_confirmed': ['order_confirmed'],
    'crypto_payment_pending': ['crypto_payment_confirmed', 'order_failed', 'expired'],
    'crypto_payment_confirmed': ['order_confirmed'],
    'order_confirmed': [],  // Terminal
    'order_failed': [],     // Terminal
    'expired': []           // Terminal
  },

  // States that must be reached before order confirmation
  requiredStatesForConfirmation: [
    'cart_validated',
    'shipping_selected'
  ],

  // Payment states that satisfy payment requirement
  validPaymentStates: [
    'card_payment_verified',
    'paypal_confirmed',
    'crypto_payment_confirmed'
  ],

  // Session timeout in milliseconds (30 minutes)
  sessionTimeout: 30 * 60 * 1000
};

class WorkflowEngine {
  constructor(config) {
    this.config = config;
    this.sessions = new Map();

    // Cleanup expired sessions every minute
    setInterval(() => this.cleanupExpiredSessions(), 60000);
  }

  createSession(userId, sessionType, cartData) {
    const sessionId = crypto.randomBytes(32).toString('hex');
    const now = Date.now();

    const session = {
      sessionId,
      userId,
      sessionType, // 'guest' or 'registered'
      state: this.config.states.INITIATED,
      stateHistory: [{
        state: this.config.states.INITIATED,
        timestamp: now,
        metadata: { sessionType }
      }],
      data: { cart: cartData },
      createdAt: now,
      lastActivity: now,
      expiresAt: now + this.config.sessionTimeout
    };

    this.sessions.set(sessionId, session);

    auditEmitter.emit('workflow_event', {
      event: 'SESSION_CREATED',
      sessionId,
      userId,
      sessionType
    });

    return session;
  }

  transition(sessionId, targetState, metadata = {}) {
    const session = this.sessions.get(sessionId);

    if (!session) {
      throw new WorkflowError('SESSION_NOT_FOUND', 'Checkout session not found');
    }

    // Check expiration
    if (Date.now() > session.expiresAt) {
      session.state = this.config.states.EXPIRED;
      auditEmitter.emit('workflow_event', {
        event: 'SESSION_EXPIRED',
        sessionId,
        userId: session.userId
      });
      throw new WorkflowError('SESSION_EXPIRED', 'Checkout session has expired');
    }

    // Validate transition is allowed
    const allowedTransitions = this.config.transitions[session.state] || [];
    if (!allowedTransitions.includes(targetState)) {
      auditEmitter.emit('workflow_event', {
        event: 'INVALID_TRANSITION_ATTEMPT',
        sessionId,
        userId: session.userId,
        currentState: session.state,
        attemptedState: targetState,
        clientIp: metadata.clientIp
      });

      throw new WorkflowError(
        'INVALID_TRANSITION',
        `Cannot transition from ${session.state} to ${targetState}`
      );
    }

    // Perform transition
    const previousState = session.state;
    session.state = targetState;
    session.lastActivity = Date.now();
    session.stateHistory.push({
      state: targetState,
      timestamp: Date.now(),
      previousState,
      metadata
    });

    auditEmitter.emit('workflow_event', {
      event: 'STATE_TRANSITION',
      sessionId,
      userId: session.userId,
      previousState,
      newState: targetState
    });

    return session;
  }

  canConfirmOrder(sessionId) {
    const session = this.sessions.get(sessionId);
    if (!session) return { valid: false, reason: 'Session not found' };

    // Check all required states were visited
    const visitedStates = session.stateHistory.map(h => h.state);

    for (const required of this.config.requiredStatesForConfirmation) {
      if (!visitedStates.includes(required)) {
        return { valid: false, reason: `Required step not completed: ${required}` };
      }
    }

    // Check payment was completed
    const hasValidPayment = this.config.validPaymentStates.some(
      state => visitedStates.includes(state)
    );

    if (!hasValidPayment) {
      return { valid: false, reason: 'Payment not completed' };
    }

    // Verify current state allows confirmation
    if (!this.config.transitions[session.state].includes(this.config.states.ORDER_CONFIRMED)) {
      return { valid: false, reason: `Current state ${session.state} does not allow confirmation` };
    }

    return { valid: true };
  }

  cleanupExpiredSessions() {
    const now = Date.now();
    for (const [sessionId, session] of this.sessions) {
      if (now > session.expiresAt && 
          !['order_confirmed', 'order_failed', 'expired'].includes(session.state)) {
        session.state = this.config.states.EXPIRED;
        auditEmitter.emit('workflow_event', {
          event: 'SESSION_CLEANUP',
          sessionId,
          userId: session.userId
        });
      }
    }
  }
}

class WorkflowError extends Error {
  constructor(code, message) {
    super(message);
    this.code = code;
  }
}

// Initialize workflow engine
const workflow = new WorkflowEngine(WORKFLOW_CONFIG);

// Middleware to extract client info
const clientInfoMiddleware = (req, res, next) => {
  req.clientInfo = {
    clientIp: req.ip,
    userAgent: req.get('User-Agent')
  };
  next();
};

app.use(clientInfoMiddleware);

// API Routes
app.post('/api/checkout/start', (req, res) => {
  try {
    const { userId, isGuest, cart } = req.body;
    const sessionType = isGuest ? 'guest' : 'registered';
    const session = workflow.createSession(userId, sessionType, cart);

    // Auto-transition to cart validated
    workflow.transition(session.sessionId, 'cart_validated', req.clientInfo);

    res.json({
      sessionId: session.sessionId,
      state: session.state,
      expiresAt: session.expiresAt,
      nextSteps: WORKFLOW_CONFIG.transitions[session.state]
    });
  } catch (error) {
    handleWorkflowError(res, error);
  }
});

app.post('/api/checkout/guest-info', (req, res) => {
  try {
    const { sessionId, email, name } = req.body;
    const session = workflow.transition(
      sessionId, 
      'guest_info_collected',
      { ...req.clientInfo, email }
    );
    session.data.guestInfo = { email, name };

    res.json({
      sessionId,
      state: session.state,
      nextSteps: WORKFLOW_CONFIG.transitions[session.state]
    });
  } catch (error) {
    handleWorkflowError(res, error);
  }
});

app.post('/api/checkout/authenticate', (req, res) => {
  try {
    const { sessionId, authToken } = req.body;

    // Verify auth token (integrate with your auth system)
    const userVerified = verifyAuthToken(authToken);
    if (!userVerified) {
      return res.status(401).json({ error: 'Invalid authentication' });
    }

    const session = workflow.transition(
      sessionId,
      'user_authenticated',
