});

app.post('/api/checkout/payment/card', async (req, res) => {
  try {
    const { sessionId, cardToken } = req.body;

    // Transition to pending state first
    let session = workflow.transition(
      sessionId,
      'card_payment_pending',
      req.clientInfo
    );

    // Process payment with provider
    const paymentResult = await processCardPayment(cardToken, session.data.cart);

    if (paymentResult.success) {
      session = workflow.transition(
        sessionId,
        'card_payment_verified',
        { transactionId: paymentResult.transactionId, ...req.clientInfo }
      );
      session.data.payment = paymentResult;

      res.json({
        sessionId,
        state: session.state,
        canConfirm: workflow.canConfirmOrder(sessionId).valid,
        nextSteps: WORKFLOW_CONFIG.transitions[session.state]
      });
    } else {
      workflow.transition(sessionId, 'order_failed', { reason: paymentResult.error });
      res.status(402).json({ error: 'Payment failed', reason: paymentResult.error });
    }
  } catch (error) {
    handleWorkflowError(res, error);
  }
});

app.post('/api/checkout/confirm', (req, res) => {
  try {
    const { sessionId } = req.body;

    // CRITICAL: Verify all requirements before confirming
    const validation = workflow.canConfirmOrder(sessionId);
    if (!validation.valid) {
      auditEmitter.emit('workflow_event', {
        event: 'CONFIRMATION_REJECTED',
        sessionId,
        reason: validation.reason,
        clientIp: req.clientInfo.clientIp
      });

      return res.status(400).json({
        error: 'Cannot confirm order',
        reason: validation.reason
      });
    }

    const session = workflow.transition(
      sessionId,
      'order_confirmed',
      req.clientInfo
    );

    const orderId = `ORD-${Date.now()}-${crypto.randomBytes(4).toString('hex')}`;

    auditEmitter.emit('workflow_event', {
      event: 'ORDER_CONFIRMED',
      sessionId,
      orderId,
      userId: session.userId,
      totalAmount: session.data.cart.total
    });

    res.json({
      orderId,
      status: 'confirmed',
      workflowHistory: session.stateHistory
    });
  } catch (error) {
    handleWorkflowError(res, error);
  }
});

function handleWorkflowError(res, error) {
  if (error instanceof WorkflowError) {
    const statusCodes = {
      'SESSION_NOT_FOUND': 404,
      'SESSION_EXPIRED': 410,
      'INVALID_TRANSITION': 400
    };
    return res.status(statusCodes[error.code] || 400).json({
      error: error.code,
      message: error.message
    });
  }
  console.error('Unexpected error:', error);
  res.status(500).json({ error: 'Internal server error' });
}

function verifyAuthToken(token) {
  // Implement actual auth verification
  return token && token.startsWith('valid_');
}

async function processCardPayment(cardToken, cart) {
  // Integrate with payment provider (Stripe, etc.)
  return { success: true, transactionId: `txn_${Date.now()}` };
}

module.exports = { app, WorkflowEngine, WORKFLOW_CONFIG };
